class Solution {
public:
    int findIntegers(int n) {
        int count = 0;
        for (int i = 0; i <= n; i++) {
            string bin = bitset<32>(i).to_string();
            if (bin.find("11") == string::npos) count++;
        }
        return count;
    }
};
```

